<?php
namespace App\Services\Production;
use App\Models\{Item,ProductionBom}; use Illuminate\Database\Eloquent\Builder;
class ProductionItemEligibility { private const OUTPUT_CODES=['FG','SFG','SEMI_FINISHED']; private const INPUT_CODES=['RM','PK','CS','SFG','SEMI_FINISHED']; public function outputQuery():Builder{return $this->base()->whereHas('category',fn(Builder$q)=>$q->whereIn('code',self::OUTPUT_CODES));} public function materialQuery(string$type):Builder{$codes=self::INPUT_CODES;if($type===ProductionBom::TYPE_REPACKING)$codes[]='FG';return $this->base()->whereHas('category',fn(Builder$q)=>$q->whereIn('code',$codes));} public function isOutput(Item$i):bool{return $this->outputQuery()->whereKey($i)->exists();} public function isMaterial(Item$i,string$type):bool{return $this->materialQuery($type)->whereKey($i)->exists();} private function base():Builder{return Item::query()->where('is_active',true)->where('track_inventory',true)->where('is_stock_item',true)->where('item_type','INVENTORY')->whereNotNull('base_unit_id');} }
